    // Create a frequency map to track how many times each index is multiplied
    const freq = new Array(n).fill(0);

    for (const [li, ri, ki, vi] of queries) {
        let idx = li;
        while (idx <= ri) {
            freq[idx] += vi;
            idx += ki;
        }
    }

    // Apply the multiplications and compute XOR
    let xorResult = 0;
    for (let i = 0; i < n; i++) {
        let val = nums[i];
        for (let j = 0; j < freq[i]; j++) {
            val = (val * vi) % MOD;
        }
        xorResult ^= val;
    }

    return xorResult;
}
